import{_ as t,a,b as d,c as s}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as i,o as l,c as n,a2 as o}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"د S3 Channel اضافه کول","description":"","frontmatter":{},"headers":[],"relativePath":"ps/upload/s3.md","filePath":"ps/upload/s3.md","lastUpdated":1781962217000}'),c={name:"ps/upload/s3.md"};function r(p,e,h,u,m,b){return l(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="د-s3-channel-اضافه-کول" tabindex="-1">د S3 Channel اضافه کول <a class="header-anchor" href="#د-s3-channel-اضافه-کول" aria-label="Permalink to &quot;د S3 Channel اضافه کول&quot;">​</a></h1><h2 id="کله-مناسب-دی" tabindex="-1">کله مناسب دی <a class="header-anchor" href="#کله-مناسب-دی" aria-label="Permalink to &quot;کله مناسب دی&quot;">​</a></h2><p>S3 channel هغه وخت وکاروئ چې:</p><ul><li>غواړئ هر S3-compatible object storage service وصل کړئ، لکه Cloudflare R2، Backblaze B2، MinIO، AWS S3 یا بل compatible provider.</li><li>د standard S3 configuration model غوره کوئ: <code>Endpoint</code>، Access Key او Secret Key.</li><li>نه غواړئ native Cloudflare R2 binding channel وکاروئ، یا ستاسې storage provider Cloudflare R2 نه وي.</li></ul><h2 id="د-پیل-مخکې-اړتیاوې" tabindex="-1">د پیل مخکې اړتیاوې <a class="header-anchor" href="#د-پیل-مخکې-اړتیاوې" aria-label="Permalink to &quot;د پیل مخکې اړتیاوې&quot;">​</a></h2><table tabindex="0"><thead><tr><th>اړتیا</th><th>موخه</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>د object storage service S3 API endpoint.</td></tr><tr><td>Bucket name</td><td>هغه bucket چې files پکې ساتل کېږي.</td></tr><tr><td>Region</td><td>storage region. د Cloudflare R2 لپاره عموماً <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td></tr><tr><td>CDN domain</td><td>د file access لپاره optional custom domain.</td></tr></tbody></table><p>د Cloudflare R2 لپاره د S3 API له لارې مثال:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: copied from the Cloudflare R2 API token</span></span>
<span class="line"><span>Secret Access Key: copied from the Cloudflare R2 API token</span></span></code></pre></div><h2 id="چېرته-یې-اضافه-کړو" tabindex="-1">چېرته یې اضافه کړو <a class="header-anchor" href="#چېرته-یې-اضافه-کړو" aria-label="Permalink to &quot;چېرته یې اضافه کړو&quot;">​</a></h2><ol><li>System Settings پرانیزئ.</li><li>Upload Settings ته ولاړ شئ.</li><li>په پورته ښي لوري کې Add Channel کلیک کړئ.</li><li><code>S3</code> وټاکئ.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>څه کوي</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>د دې S3 channel لپاره پېژندل کېدونکی نوم، لکه <code>s3test</code> یا <code>R2-S3</code>.</td><td>Yes</td></tr><tr><td>Enable channel</td><td>کنټرولوي چې دا channel په upload selection کې ګډون وکړي که نه.</td><td>Recommended</td></tr><tr><td>Endpoint</td><td>بشپړ S3 service endpoint د <code>https://</code> سره.</td><td>Yes</td></tr><tr><td>Custom CDN domain</td><td>اختیاري. که set شي، generated file links به دا domain غوره کړي.</td><td>No</td></tr><tr><td>Bucket name</td><td>bucket name، لکه <code>s3test</code> یا <code>img-r2</code>.</td><td>Yes</td></tr><tr><td>Bucket region</td><td>Region. د Cloudflare R2 لپاره عموماً <code>auto</code>.</td><td>Yes</td></tr><tr><td>Access Key ID</td><td>S3 access key ID.</td><td>Yes</td></tr><tr><td>Secret Access Key</td><td>S3 secret access key.</td><td>Yes</td></tr><tr><td>Path-style access</td><td>compatibility switch. default off دی. ځینې MinIO، OpenList یا self-hosted S3 services یې غواړي.</td><td>No</td></tr><tr><td>Quota limit</td><td>کنټرولوي چې دا S3 channel د capacity له مخې upload selection کې ګډون وکړي که نه.</td><td>No</td></tr><tr><td>Capacity limit</td><td>د quota limit له enable وروسته required، لکه <code>10 GB</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Threshold</td><td>کله چې usage دې percentage ته ورسېږي write بندوي، لکه <code>90%</code>.</td><td>Required when quota limit is enabled</td></tr><tr><td>Remark</td><td>د خپل maintenance لپاره یادښتونه.</td><td>No</td></tr></tbody></table><h2 id="cloudflare-r2-s3-api-keys-جوړ-کړئ" tabindex="-1">Cloudflare R2 S3 API Keys جوړ کړئ <a class="header-anchor" href="#cloudflare-r2-s3-api-keys-جوړ-کړئ" aria-label="Permalink to &quot;Cloudflare R2 S3 API Keys جوړ کړئ&quot;">​</a></h2><ol><li>Cloudflare Dashboard پرانیزئ.</li><li><code>R2 Object Storage</code> ته ولاړ شئ.</li><li><code>Manage R2 API Tokens</code> یا API token management entry ومومئ.</li></ol><p>![R2 API token entry](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>داسې R2 API token جوړ کړئ چې target bucket ته access ولري.</li></ol><p><img src="`+t+'" alt="Create an account API token" loading="lazy"></p><ol start="5"><li>generated <code>Access Key ID</code> او <code>Secret Access Key</code> copy کړئ.</li></ol><p><img src="'+a+'" alt="Copy the token values" loading="lazy"></p><ol start="6"><li>R2 bucket page ته بېرته ولاړ شئ او bucket name confirm کړئ.</li><li>د account لپاره S3 API endpoint ولیکئ. عموماً داسې ښکاري:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings پرانیزئ.</li><li>Add Channel کلیک کړئ.</li><li><code>S3</code> وټاکئ.</li><li>یو پېژندل کېدونکی channel name ولیکئ، لکه <code>s3test</code>.</li><li>S3 API endpoint په <code>Endpoint</code> کې ولیکئ.</li><li>که custom CDN لرئ، په <code>Custom CDN domain</code> کې یې ولیکئ؛ که نه، خالي یې پرېږدئ.</li><li>bucket name ولیکئ.</li><li>region ولیکئ. د Cloudflare R2 مثال لپاره <code>auto</code> وکاروئ.</li><li>Access Key ID او Secret Access Key ولیکئ.</li><li>path-style access off پرېږدئ، مګر provider یې صریحاً وغواړي.</li><li>که capacity control غواړئ، quota limit enable کړئ او capacity limit او threshold ولیکئ.</li><li>Save کلیک کړئ.</li></ol><p><img src="'+d+'" alt="Add S3 configuration" loading="lazy"></p><h2 id="څنګه-یې-verify-کړو" tabindex="-1">څنګه یې Verify کړو <a class="header-anchor" href="#څنګه-یې-verify-کړو" aria-label="Permalink to &quot;څنګه یې Verify کړو&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>د verify طریقه</th></tr></thead><tbody><tr><td>Channel card appears</td><td>له Save وروسته Upload Settings باید S3 channel card وښيي.</td></tr><tr><td>Channel is enabled</td><td>د card په پورته ښي لوري کې switch باید on پاتې شي.</td></tr><tr><td>Key fields are saved</td><td>detail view باید Endpoint، Bucket، Region، path-style access او اړوند fields وښيي.</td></tr><tr><td>Upload works</td><td>test image upload کړئ او confirm کړئ چې object په target bucket کې جوړ شوی.</td></tr><tr><td>Link opens</td><td>له upload وروسته returned image link باید عادي پرانستل شي.</td></tr><tr><td>Capacity display works</td><td>که quota limit enabled وي، card باید used capacity او configured limit وښيي.</td></tr></tbody></table><p>S3 capacity statistics د provider bucket real time query نه کوي، بلکې د ImgBed local file records څخه حسابېږي. د S3 configuration له save وروسته system د current D1 records څخه quota ledger بیا محاسبه کوي.</p><p><img src="'+s+`" alt="Quota query succeeded" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="path-style-access-enable-کړم؟" tabindex="-1">path-style access enable کړم؟ <a class="header-anchor" href="#path-style-access-enable-کړم؟" aria-label="Permalink to &quot;path-style access enable کړم؟&quot;">​</a></h3><p>عموماً نه.</p><p>یوازې هغه وخت یې enable کړئ چې S3-compatible provider مو virtual-hosted-style URLs نه support کوي، یا provider documentation صریحاً path-style access غواړي.</p><h3 id="cdn-domain-د-څه-لپاره-دی؟" tabindex="-1">CDN domain د څه لپاره دی؟ <a class="header-anchor" href="#cdn-domain-د-څه-لپاره-دی؟" aria-label="Permalink to &quot;CDN domain د څه لپاره دی؟&quot;">​</a></h3><p>که د bucket مخې ته CDN یا custom access domain لرئ، دلته یې ولیکئ.</p><p>له configure وروسته generated file links به دا domain غوره کړي. که CDN نه کاروئ، field خالي پرېږدئ.</p><h3 id="ولې-upload-fail-کېږي؟" tabindex="-1">ولې upload fail کېږي؟ <a class="header-anchor" href="#ولې-upload-fail-کېږي؟" aria-label="Permalink to &quot;ولې upload fail کېږي؟&quot;">​</a></h3><p>لومړی دا وګورئ:</p><ol><li>Endpoint د <code>https://</code> سره بشپړ URL لري.</li><li>bucket name سم دی.</li><li>Region د provider requirement سره برابر دی.</li><li>Access Key ID او Secret Access Key بشپړ copy شوي.</li><li>key د target bucket لپاره write permission لري.</li><li>provider path-style access نه غواړي، یا که غواړي enabled دی.</li></ol><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S3 Endpoint, Bucket, Region, Access Key او Secret Key چمتو کړئ</span></span>
<span class="line"><span>-&gt; Upload Settings پرانیزئ</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; S3 وټاکئ</span></span>
<span class="line"><span>-&gt; Endpoint / Bucket / Region / Access Key / Secret Key ولیکئ</span></span>
<span class="line"><span>-&gt; که اړتیا وي CDN domain ولیکئ</span></span>
<span class="line"><span>-&gt; path-style access default off پرېږدئ</span></span>
<span class="line"><span>-&gt; که اړتیا وي quota limit enable کړئ</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; test image upload او result وګورئ</span></span></code></pre></div>`,40)])])}const k=i(c,[["render",r]]);export{y as __pageData,k as default};
